USE culinary_user;

REPLACE INTO t_rcp_info (id, author_id, title, cover_url, video_url, description, category_id, cuisine_id, difficulty, time_cost, calories, protein, fat, carbs, score, view_count, like_count, collect_count, comment_count, share_count, try_count, status, tags, tips, is_exclusive, is_paid, price, publish_time, ip_location, device_info, gmt_create, gmt_modified, is_deleted, version)
VALUES
(3900000, 2000000, '川菜·麻婆豆腐', 'https://images.unsplash.com/photo-1625938146364-3c3c7f0f8c5e?auto=format&fit=crop&w=1600&q=80', '', '麻辣鲜香、下饭必备。豆腐嫩滑，花椒麻、辣椒香，适合新手练习“滑嫩不碎”。', 5, NULL, 2, 25, 420, 22.0, 24.0, 18.0, 4.8, 1200, 88, 55, 12, 6, 18, 2, '[\"中式\",\"川菜\",\"麻婆豆腐\",\"下饭\",\"麻辣\"]', '豆腐先焯水更不易碎；最后勾薄芡更顺滑。', 0, 0, 0.00, NOW(3), '成都', 'Windows 网页端', NOW(3), NOW(3), 0, 1),
(3900001, 2000000, '川菜·宫保鸡丁', 'https://images.unsplash.com/photo-1604908177522-040b2e6c7ad7?auto=format&fit=crop&w=1600&q=80', '', '酸甜微辣，花生酥脆。掌握“先滑后炒”与“宫保汁比例”，快速出锅不老。', 5, NULL, 2, 30, 520, 38.0, 28.0, 22.0, 4.7, 980, 72, 41, 9, 3, 12, 2, '[\"中式\",\"川菜\",\"宫保鸡丁\",\"快炒\",\"花生\"]', '鸡丁先上浆滑炒；花生最后下，保持酥脆。', 0, 0, 0.00, NOW(3), '成都', '安卓手机', NOW(3), NOW(3), 0, 1),
(3900002, 2000001, '粤菜·白切鸡', 'https://images.unsplash.com/photo-1601050690597-3a3b4d2fd3c8?auto=format&fit=crop&w=1600&q=80', '', '皮爽肉嫩、原汁原味。关键在“控温浸熟”和“冰水紧皮”，蘸姜葱油更香。', 6, NULL, 2, 55, 610, 46.0, 32.0, 12.0, 4.6, 860, 50, 36, 5, 1, 6, 2, '[\"中式\",\"粤菜\",\"白切鸡\",\"清淡\",\"家常\"]', '鸡出锅立刻冰水浸泡 3 分钟，皮更脆。', 0, 0, 0.00, NOW(3), '广州', 'iPhone', NOW(3), NOW(3), 0, 1),
(3900003, 2000001, '湘菜·剁椒鱼头', 'https://images.unsplash.com/photo-1617196034796-73c0f2f28ed6?auto=format&fit=crop&w=1600&q=80', '', '鲜辣开胃，蒸出来的鱼肉细嫩。剁椒铺满、蒸制到位，最后热油激香。', 7, NULL, 3, 35, 680, 48.0, 36.0, 18.0, 4.7, 740, 62, 49, 8, 2, 9, 2, '[\"中式\",\"湘菜\",\"剁椒鱼头\",\"蒸菜\",\"鲜辣\"]', '鱼头提前抹盐和料酒腌 10 分钟去腥。', 0, 0, 0.00, NOW(3), '长沙', '安卓平板', NOW(3), NOW(3), 0, 1),
(3900004, 2000002, '浙菜·东坡肉', 'https://images.unsplash.com/photo-1604909054020-9a2a93c2d96a?auto=format&fit=crop&w=1600&q=80', '', '肥而不腻、入口即化。小火慢炖收汁，酒香与酱香融入五花肉纤维。', 1, NULL, 4, 150, 980, 28.0, 78.0, 18.0, 4.9, 620, 90, 80, 16, 4, 25, 2, '[\"中式\",\"浙菜\",\"东坡肉\",\"红烧\",\"宴客\"]', '全程小火，避免翻动过多导致散块。', 0, 0, 0.00, NOW(3), '杭州', 'Mac 浏览器', NOW(3), NOW(3), 0, 1),
(3900005, 2000002, '苏菜·红烧狮子头', 'https://images.unsplash.com/photo-1604908177064-6c3fe2c2c9b0?auto=format&fit=crop&w=1600&q=80', '', '软糯多汁、汤汁浓郁。肉馅搅打上劲，先定型再小火焖煮。', 1, NULL, 3, 90, 860, 32.0, 58.0, 20.0, 4.6, 540, 44, 33, 6, 1, 8, 2, '[\"中式\",\"苏菜\",\"狮子头\",\"红烧\",\"家宴\"]', '肉馅顺一个方向搅打 3-5 分钟更弹。', 0, 0, 0.00, NOW(3), '南京', 'Windows 网页端', NOW(3), NOW(3), 0, 1),
(3900006, 2000003, '陕味·肉夹馍（家常版）', 'https://images.unsplash.com/photo-1604908176464-1c65c2d0b9b3?auto=format&fit=crop&w=1600&q=80', '', '外酥里软、肉香四溢。卤肉可提前做，现烤白吉馍夹入更满足。', 1, NULL, 2, 80, 720, 30.0, 42.0, 70.0, 4.5, 900, 66, 52, 9, 2, 14, 2, '[\"中式\",\"陕西\",\"肉夹馍\",\"小吃\",\"碳水快乐\"]', '卤肉切碎拌少许卤汁，夹馍更润。', 0, 0, 0.00, NOW(3), '西安', 'HarmonyOS', NOW(3), NOW(3), 0, 1),
(3900007, 2000003, '东北·锅包肉', 'https://images.unsplash.com/photo-1540189549336-e6e99c3679fe?auto=format&fit=crop&w=1600&q=80', '', '外酥里嫩、酸甜开胃。淀粉糊要挂牢，复炸更酥，最后快速裹汁出锅。', 1, NULL, 3, 45, 830, 35.0, 46.0, 55.0, 4.6, 700, 58, 40, 7, 1, 10, 2, '[\"中式\",\"东北\",\"锅包肉\",\"酸甜\",\"炸物\"]', '裹汁后只翻几下立刻出锅，保持酥脆。', 0, 0, 0.00, NOW(3), '哈尔滨', '安卓手机', NOW(3), NOW(3), 0, 1),
(3900008, 2000004, '新疆·大盘鸡', 'https://images.unsplash.com/photo-1604908177472-9a9c2b8a4f12?auto=format&fit=crop&w=1600&q=80', '', '香辣浓郁、土豆入味。先煸香再炖煮，最后拌皮带面更地道。', 1, NULL, 3, 80, 920, 46.0, 44.0, 60.0, 4.8, 560, 70, 61, 11, 2, 16, 2, '[\"中式\",\"新疆\",\"大盘鸡\",\"炖煮\",\"土豆\"]', '土豆后下防碎；收汁阶段勤翻动避免糊锅。', 0, 0, 0.00, NOW(3), '乌鲁木齐', 'Windows 网页端', NOW(3), NOW(3), 0, 1),
(3900009, 2000004, '云南·过桥米线（简化版）', 'https://images.unsplash.com/photo-1604908177326-8e651b02e6ed?auto=format&fit=crop&w=1600&q=80', '', '汤清味鲜、配料丰富。高汤滚烫保持温度，依次下料“先生后熟”。', 1, NULL, 2, 35, 560, 26.0, 18.0, 82.0, 4.7, 820, 59, 47, 10, 3, 11, 2, '[\"中式\",\"云南\",\"过桥米线\",\"汤羹\",\"鲜香\"]', '先下薄肉片与蔬菜，再下米线，口感层次更好。', 0, 0, 0.00, NOW(3), '昆明', 'iPad', NOW(3), NOW(3), 0, 1);

REPLACE INTO t_rcp_step (id, recipe_id, step_no, `desc`, img_url, video_url, time_cost, is_key_step, voice_url, gmt_create) VALUES
(390000001, 3900000, 1, '豆腐切 2cm 小块，淡盐水中轻轻焯 1 分钟，沥干备用。', NULL, NULL, 5, 1, NULL, NOW(3)),
(390000002, 3900000, 2, '热锅少油，下葱姜蒜炒香，加入郫县豆瓣酱小火炒出红油。', NULL, NULL, 4, 1, NULL, NOW(3)),
(390000003, 3900000, 3, '加入少量清水，放入豆腐轻推，调入生抽、少许糖，小火煮 3 分钟入味。', NULL, NULL, 6, 0, NULL, NOW(3)),
(390000004, 3900000, 4, '薄芡水淀粉分两次勾入，轻推至汤汁浓稠；撒花椒面与葱花，出锅。', NULL, NULL, 5, 1, NULL, NOW(3)),

(390000101, 3900001, 1, '鸡腿肉切丁，加盐、生抽、淀粉、少许油抓匀上浆 10 分钟。', NULL, NULL, 10, 1, NULL, NOW(3)),
(390000102, 3900001, 2, '调宫保汁：生抽 2 勺、陈醋 2 勺、白糖 2 勺、料酒 1 勺、少许淀粉与清水。', NULL, NULL, 4, 0, NULL, NOW(3)),
(390000103, 3900001, 3, '热锅宽油滑炒鸡丁至变色盛出；留底油下干辣椒与花椒炒香。', NULL, NULL, 6, 1, NULL, NOW(3)),
(390000104, 3900001, 4, '下葱段与黄瓜丁翻炒，倒入鸡丁与宫保汁快速翻匀，最后下花生米出锅。', NULL, NULL, 6, 1, NULL, NOW(3)),

(390000201, 3900002, 1, '整鸡清洗干净，抹盐与姜片腌 10 分钟；锅中加水没过鸡。', NULL, NULL, 10, 1, NULL, NOW(3)),
(390000202, 3900002, 2, '水微沸后放入整鸡，小火保持“似开非开”浸煮 25-30 分钟至熟。', NULL, NULL, 30, 1, NULL, NOW(3)),
(390000203, 3900002, 3, '捞出立刻入冰水浸 3 分钟，再晾干抹少许熟油，切块装盘。', NULL, NULL, 6, 1, NULL, NOW(3)),
(390000204, 3900002, 4, '姜葱切末加热油激香，少许盐调匀作蘸料。', NULL, NULL, 5, 0, NULL, NOW(3)),

(390000301, 3900003, 1, '鱼头对半劈开，抹盐和料酒腌 10 分钟；盘底铺姜片。', NULL, NULL, 10, 1, NULL, NOW(3)),
(390000302, 3900003, 2, '鱼头摆盘，铺满剁椒与少许蒜末，淋少量油。', NULL, NULL, 6, 1, NULL, NOW(3)),
(390000303, 3900003, 3, '水开上锅大火蒸 12-15 分钟；出锅撒葱花，热油一泼激香。', NULL, NULL, 15, 1, NULL, NOW(3)),

(390000401, 3900004, 1, '五花肉切大块焯水 5 分钟去浮沫，捞出冲洗干净。', NULL, NULL, 10, 1, NULL, NOW(3)),
(390000402, 3900004, 2, '锅中少油，下肉皮朝下煎至微黄；加入葱姜与冰糖炒至焦糖色。', NULL, NULL, 10, 1, NULL, NOW(3)),
(390000403, 3900004, 3, '加酱油与黄酒/料酒没过肉，小火慢炖 90 分钟；收汁至油亮。', NULL, NULL, 90, 1, NULL, NOW(3)),

(390000501, 3900005, 1, '肥瘦相间猪肉剁成馅，加葱姜水、盐、生抽顺一个方向搅打上劲。', NULL, NULL, 15, 1, NULL, NOW(3)),
(390000502, 3900005, 2, '团成大丸子，下油锅小火煎至表面定型微黄。', NULL, NULL, 10, 1, NULL, NOW(3)),
(390000503, 3900005, 3, '砂锅中放白菜垫底，加入丸子、酱油与热水，小火焖 40 分钟收汁。', NULL, NULL, 40, 1, NULL, NOW(3)),

(390000601, 3900006, 1, '五花肉切块焯水，加入葱姜、香料与酱油小火卤 60 分钟至软烂。', NULL, NULL, 60, 1, NULL, NOW(3)),
(390000602, 3900006, 2, '白吉馍切开回烤至外酥内软；卤肉剁碎拌卤汁。', NULL, NULL, 12, 1, NULL, NOW(3)),
(390000603, 3900006, 3, '将肉装入馍中，按喜好加青椒碎或香菜碎。', NULL, NULL, 5, 0, NULL, NOW(3)),

(390000701, 3900007, 1, '里脊切片拍松，裹淀粉糊下锅炸至金黄，捞出复炸 20 秒更酥。', NULL, NULL, 15, 1, NULL, NOW(3)),
(390000702, 3900007, 2, '调酸甜汁：番茄酱、白糖、白醋与少量水淀粉，小火煮至冒泡。', NULL, NULL, 6, 1, NULL, NOW(3)),
(390000703, 3900007, 3, '倒入炸好的肉片快速翻匀裹汁，立刻出锅。', NULL, NULL, 4, 1, NULL, NOW(3)),

(390000801, 3900008, 1, '鸡块焯水去腥；热锅下油，爆香葱姜蒜与香料。', NULL, NULL, 10, 1, NULL, NOW(3)),
(390000802, 3900008, 2, '下鸡块翻炒上色，加入酱油、辣椒与热水，小火炖 25 分钟。', NULL, NULL, 25, 1, NULL, NOW(3)),
(390000803, 3900008, 3, '下土豆块再炖 15 分钟，收汁至浓稠；可拌皮带面食用。', NULL, NULL, 20, 1, NULL, NOW(3)),

(390000901, 3900009, 1, '高汤煮沸保持滚烫；米线另锅煮熟过凉水备用。', NULL, NULL, 10, 1, NULL, NOW(3)),
(390000902, 3900009, 2, '将薄肉片、蔬菜、豆腐皮等配料切好，按“先生后熟”顺序下入高汤中烫熟。', NULL, NULL, 10, 1, NULL, NOW(3)),
(390000903, 3900009, 3, '下入米线与调味（盐/胡椒/葱花），装碗即食。', NULL, NULL, 8, 0, NULL, NOW(3));

